function mt(){return {babyName:"",babyBirthDate:"",foods:{},rx:{},meals:{}};}
async function ldb(){try{if(!window.storage)return mt();var r;try{r=await window.storage.get(SK);}catch(e){r=null;}if(r&&r.value){var d=JSON.parse(r.value);if(!d.foods)d.foods={};if(!d.rx)d.rx={};if(!d.meals)d.meals={};return d;}try{r=await window.storage.get("blw-tracker-v2");}catch(e){r=null;}if(r&&r.value){var x=JSON.parse(r.value);var m={babyName:x.babyName||"",babyBirthDate:x.babyBirthDate||"",foods:x.introducedFoods||{},rx:x.reactions||{},meals:{}};try{await window.storage.set(SK,JSON.stringify(m));}catch(e){}return m;}return mt();}catch(e){return mt();}}
async function svdb(d){try{if(window.storage)await window.storage.set(SK,JSON.stringify(d));}catch(e){}}
function ga(bd){if(!bd)return 6;var b=new Date(bd),n=new Date();return(n.getFullYear()-b.getFullYear())*12+n.getMonth()-b.getMonth();}
function da(ds){return Math.floor((new Date()-new Date(ds))/864e5);}
function fm(ds){return new Date(ds).toLocaleDateString("es-ES",{day:"numeric",month:"long"});}
function fmf(ds){return new Date(ds).toLocaleDateString("es-ES",{weekday:"long",day:"numeric",month:"long"});}
function dky(y,m,d){return y+"-"+String(m+1).padStart(2,"0")+"-"+String(d).padStart(2,"0");}
function cdy(y,m){var ds=[],fd=new Date(y,m,1),ld=new Date(y,m+1,0),s=(fd.getDay()+6)%7;for(var i=0;i<s;i++)ds.push(null);for(var d=1;d<=ld.getDate();d++)ds.push(d);return ds;}
function gf(id){for(var i=0;i<FOODS.length;i++)if(FOODS[i].id===id)return FOODS[i];return null;}

